      { "name": "Payment Processor", "responsibility": "Executes payment logic — authorization, capture, settlement — operating on encrypted-at-rest data, decrypting only through Crypto Envelope Service", "boundaries": "Business logic only; never handles raw key material; depends on Crypto Envelope Service for all encrypt/decrypt" },
      { "name": "Audit Logger", "responsibility": "Records every field access and mutation with caller identity, timestamp, field name, and operation type", "boundaries": "Append-only; receives events from all components; must not block the hot path (design TBD pending contradiction resolution)" },
      { "name": "Key Rotation Controller", "responsibility": "Orchestrates zero-downtime key rotation — generates new DEKs, re-encrypts data in background, maintains dual-read capability during transition", "boundaries": "Background process; never interrupts live payment flow; coordinates with Crypto Envelope Service" },
      { "name": "Offline Key Cache", "responsibility": "Securely caches wrapped DEKs and their plaintext counterparts in a hardware-backed local store (TPM/HSM) for use when external KMS is unreachable", "boundaries": "Bounded TTL on cached keys; encrypted at rest using node-local hardware keys; design TBD pending contradiction resolution on revocation semantics" }
